{
    if (g_effect_laser_set_track_goal)
        g_effect_laser_set_track_goal(Int_val(v_objnum), Int_val(v_goal_obj));
    return Val_unit;
}

/* p_rand: unit -> int */
CAMLprim value cd_ox_effect_p_rand(value unit)
{
    (void)unit;
    int result = 0;
    if (g_effect_laser_p_rand)
